'"""\nNDR告警研判工作流测试\n\n测试NDR告警研判工作流的各个组件和完整流程\n"""\n\nimport json\nimport pytest\nfrom pathlib import Path\nfrom typing import Any, Dict\n\nfrom flocks.workflow import load_workflow, run_workflow, Workflow\nfrom flocks.workflow.runner import RunWorkflowResult\n\n\n# ==================== 测试数据和Fixtures ====================\n\n@pytest.fixture\ndef workflow_file() -> Path:\n    """工作流文件路径"""\n    return Path(__file__).parent.parent / "examples" / "ndr_alert_analysis_workflow.yaml"\n\n\n@pytest.fixture\ndef sample_malware_alert() -> Dict[str, Any]:\n    """示例恶意软件告警数据"""\n    return {\n        "alert_data": {\n            "timestamp": "2026-02-12T08:30:00Z",\n            "description": "Detected suspicious file execution with known malware signature",\n            "event_id": "EVT-20260212-001",\n            "file_info": {\n                "filename": "update.exe",\n                "md5": "d41d8cd98f00b204e9800998ecf8427e",\n                "sha256": "e3b0c44298fc1c149afbf4c8996fb92427ae41e4649b934ca495991b7852b855"\n            }\n        },\n        "alert_type": "malware",\n        "source_ip": "192.168.100.50",\n        "destination_ip": "192.168.100.10",\n        "severity": "high"\n    }\n\n\n@pytest.fixture\ndef sample_c2_alert() -> Dict[str, Any]:\n    """示例C2通信告警数据"""\n    return {\n        "alert_data": {\n            "timestamp": "2026-02-12T10:15:00Z",\n            "description": "Suspicious beaconing pattern detected matching known APT C2 signature",\n            "event_id": "EVT-20260212-002",\n            "c2_details": {\n                "beacon_interval": 300,\n                "jitter": 30,\n                "domain": "cdn-updateservice.com",\n                "uri": "/api/v1/check",\n                "user_agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64)"\n            }\n        },\n        "alert_type": "c2",\n        "source_ip": "192.168.100.10",\n        "destination_ip": "192.168.100.20",\n        "severity": "critical"\n    }\n\n\n@pytest.fixture\ndef sample_low_risk_alert() -> Dict[str, Any]:\n    """示例低风险告警数据"""\n    return {\n        "alert_data": {\n            "timestamp": "2026-02-12T14:20:00Z",\n            "description": "Minor port scanning activity detected from internal network",\n            "event_id": "EVT-20260212-003"\n        },\n        "alert_type": "scanning",\n        "source_ip": "192.168.1.100",\n        "severity": "low"\n    }\n\n\n# ==================== 组件测试 ====================\n\nclass TestNDRWorkflowStructure:\n    """测试NDR工作流结构完整性"""\n\n    def test_workflow_file_exists(self, workflow_file: Path):\n        """测试工作流文件存在"""\n        assert workflow_file.exists(), f"工作流文件不存在: {workflow_file}"\n\n    def test_workflow_can_load(self, workflow_file: Path):\n        """测试工作流可以被加载"""\n        workflow = load_workflow(workflow_file)\n        assert isinstance(workflow, Workflow)\n        assert workflow.name == "NDR告警研判工作流"\n\n    def test_workflow_has_all_nodes(self, workflow_file: Path):\n        """测试工作流包含所有必要的节点"""\n        workflow = load_workflow(workflow_file)\n        \n        expected_nodes = [\n            "extract_alert_info",\n            "threat_intel_lookup",\n            "asset_correlation",\n            "risk_assessment",\n            "generate_conclusion",\n            "generate_recommendations",\n            "generate_report"\n        ]\n        \n        node_ids = {node.id for node in workflow.nodes}\n        for expected in expected_nodes:\n            assert expected in node_ids, f"缺少节点: {expected}"\n\n    def test_workflow_edges_connectivity(self, workflow_file: Path):\n        """测试工作流边的连通性"""\n        workflow = load_workflow(workflow_file)\n        \n        # 获取所有节点ID\n        node_ids = {node.id for node in workflow.nodes}\n        \n        # 检查每条边的from和to节点都存在\n        for edge in workflow.edges:\n            assert edge.from_ in node_ids, f"边的起始节点不存在: {edge.from_}"\n            assert edge.to in node_ids, f"边的目标节点不存在: {edge.to}"\n\n        # 检查从start节点可以到达所有节点\n        reachable = {workflow.start}\n        changed = True\n        while changed:\n            changed = False\n            for edge in workflow.edges:\n                if edge.from_ in reachable and edge.to not in reachable:\n                    reachable.add(edge.to)\n                    changed = True\n        \n        assert reachable == node_ids, "存在不可达的节点"\n\n\nclass TestNDRWorkflowExecution:\n    """测试NDR工作流执行功能"""\n\n    @pytest.mark.slow\n    def test_workflow_execution_malware_alert(\n        self, \n        workflow_file: Path, \n        sample_malware_alert: Dict[str, Any]\n    ):\n        """测试恶意软件告警的完整工作流执行"""\n        result = run_workflow(\n            workflow=workflow_file,\n            inputs=sample_malware_alert,\n            trace=False\n        )\n        \n        assert isinstance(result, RunWorkflowResult)\n        assert result.status == "SUCCEEDED", f"工作流执行失败: {result.error}"\n        assert result.steps > 0\n        assert result.outputs is not None\n        \n        # 验证输出包含关键字段\n        assert "analysis_report" in result.outputs\n        assert "report_summary" in result.outputs\n        assert "risk_score" in result.outputs\n        assert "risk_level" in result.outputs\n        assert "recommended_actions" in result.outputs\n        assert "ioc_list" in result.outputs\n\n    @pytest.mark.slow\n    def test_workflow_execution_c2_alert(\n        self, \n        workflow_file: Path, \n        sample_c2_alert: Dict[str, Any]\n    ):\n        """测试C2通信告警的完整工作流执行"""\n        result = run_workflow(\n            workflow=workflow_file,\n            inputs=sample_c2_alert,\n            trace=False\n        )\n        \n        assert result.status == "SUCCEEDED", f"工作流执行失败: {result.error}"\n        assert "analysis_report" in result.outputs\n        assert "ioc_list" in result.outputs\n        \n        # C2告警应该有更高级别的风险评分\n        risk_score = result.outputs.get("risk_score", 0)\n        assert risk_score > 0, "风险评分应该大于0"\n\n    @pytest.mark.slow\n    def test_workflow_execution_low_risk_alert(\n        self, \n        workflow_file: Path, \n        sample_low_risk_alert: Dict[str, Any]\n    ):\n        """测试低风险告警的工作流执行"""\n        result = run_workflow(\n            workflow=workflow_file,\n            inputs=sample_low_risk_alert,\n            trace=False\n        )\n        \n        assert result.status == "SUCCEEDED", f"工作流执行失败: {result.error}"\n        assert "analysis_report" in result.outputs\n        \n        # 低风险告警应该有较低的风险评分\n        risk_level = result.outputs.get("risk_level", "high")\n        assert risk_level in ["low", "medium"], "低风险告警应该产生低或中等风险评级"\n\n    @pytest.mark.slow\n    def test_workflow_execution_with_trace(\n        self, workflow_file: Path, sample_malware_alert: Dict[str, Any]):\n        """测试启用trace模式的工作流执行"""\n        # 注意: trace模式会在控制台输出执行日志\n        result = run_workflow(\n            workflow=workflow_file,\n            inputs=sample_malware_alert,\n            trace=True  # 启用执行跟踪\n        )\n        \n        assert result.status == "SUCCEEDED"\n        assert result.steps > 0\n\n    def test_workflow_invalid_alert_data(\n        self, \n        workflow_file: Path\n    ):\n        """测试无效告警数据的处理"""\n        # 使用无效的输入数据\n        invalid_inputs = {\n            "alert_data": "invalid_json_string",\n            "alert_type": None,\n            "source_ip": "not_an_ip"\n        }\n        \n        # 工作流应该能够处理并返回结果（而不是崩溃）\n        result = run_workflow(\n            workflow=workflow_file,\n            inputs=invalid_inputs,\n            trace=False\n        )\n        \n        # 即使数据有问题，工作流也应该完成执行\n        assert result.status == "SUCCEEDED"\n        assert "analysis_report" in result.outputs\n\n\nclass TestNDRWorkflowReportOutput:\n    """测试NDR工作流报告输出质量"""\n\n    @pytest.mark.slow\n    def test_report_structure_completeness(\n        self, \n        workflow_file: Path, \n        sample_malware_alert: Dict[str, Any]\n    ):\n        """测试报告结构完整性"""\n        result = run_workflow(\n            workflow=workflow_file,\n            inputs=sample_malware_alert,\n            trace=False\n        )\n        \n        report = result.outputs.get("analysis_report", {})\n        \n        # 验证报告包含所有必需的部分\n        required_sections = [\n            "report_metadata",\n            "executive_summary",\n            "detailed_analysis",\n            "risk_calculation_details",\n            "recommendations",\n            "next_steps"\n        ]\n        \n        for section in required_sections:\n            assert section in report, f"报告缺少{section}部分"\n\n    @pytest.mark.slow\n    def test_ioc_extraction_quality(\n        self, \n        workflow_file: Path, \n        sample_malware_alert: Dict[str, Any]\n    ):\n        """测试IOC提取质量"""\n        result = run_workflow(\n            workflow=workflow_file,\n            inputs=sample_malware_alert,\n            trace=False\n        )\n        \n        ioc_list = result.outputs.get("ioc_list", [])\n        report = result.outputs.get("analysis_report", {})\n        \n        # 验证IOC列表不为空\n        assert len(ioc_list) > 0, "应该提取到至少一个IOC"\n        \n        # 验证IOC结构完整性\n        for ioc in ioc_list:\n            assert "type" in ioc, "IOC必须包含type字段"\n            assert "value" in ioc, "IOC必须包含value字段"\n            assert "threat_score" in ioc, "IOC必须包含threat_score字段"\n        \n        # 验证报告中的IOC分析\n        ioc_analysis = report.get("detailed_analysis", {}).get("ioc_analysis", {})\n        assert "total_iocs" in ioc_analysis\n        assert "iocs_by_type" in ioc_analysis\n        assert ioc_analysis["total_iocs"] == len(ioc_list)\n\n    @pytest.mark.slow\n    def test_risk_calculation_accuracy(\n        self, \n        workflow_file: Path, \n        sample_c2_alert: Dict[str, Any]\n    ):\n        """测试风险计算准确性"""\n        result = run_workflow(\n            workflow=workflow_file,\n            inputs=sample_c2_alert,\n            trace=False\n        )\n        \n        risk_score = result.outputs.get("risk_score", 0)\n        risk_level = result.outputs.get("risk_level", "low")\n        report = result.outputs.get("analysis_report", {})\n        \n        # C2告警应该有较高的风险评分\n        assert risk_score > 40, f"C2告警的风险评分应该大于40，实际为{risk_score}"\n        assert risk_level in ["medium", "high", "critical"], f"C2告警应该有较高的风险等级，实际为{risk_level}"\n        \n        # 验证风险计算详情\n        calc_details = report.get("risk_calculation_details", {})\n        assert "threat_intel_weight" in calc_details\n        assert "severity_weight" in calc_details\n        assert "criticality_weight" in calc_details\n        assert "exposure_weight" in calc_details\n        assert "impact_weight" in calc_details\n\n        # 验证权重之和为1\n        total_weight = (\n            calc_details.get("threat_intel_weight", 0) +\n            calc_details.get("severity_weight", 0) +\n            calc_details.get("criticality_weight", 0) +\n            calc_details.get("exposure_weight", 0) +\n            calc_details.get("impact_weight", 0)\n        )\n        assert abs(total_weight - 1.0) < 0.01, f"权重之和应该约等于1，实际为{total_weight}"\n\n    @pytest.mark.slow\n    def test_recommendation_quality(\n        self, \n        workflow_file: Path, \n        sample_malware_alert: Dict[str, Any]\n    ):\n        """测试响应建议质量"""\n        result = run_workflow(\n            workflow=workflow_file,\n            inputs=sample_malware_alert,\n            trace=False\n        )\n        \n        recommendations = result.outputs.get("recommendations", {})\n        report = result.outputs.get("analysis_report", {})\n        \n        # 验证建议分类\n        assert "immediate_actions" in recommendations\n        assert "short_term_actions" in recommendations\n        assert "long_term_measures" in recommendations\n        assert "monitoring_suggestions" in recommendations\n        \n        # 高严重性告警应该有立即操作\n        assert len(recommendations["immediate_actions"]) > 0, "高严重性告警应该有立即操作"\n        \n        # 验证立即操作的优先级\n        for action in recommendations["immediate_actions"]:\n            assert "priority" in action or "action" in action\n            if "priority" in action:\n                assert isinstance(action["priority"], int)\n                assert 1 <= action["priority"] <= 10\n        \n        # 验证工作量估计\n        assert "estimated_effort" in recommendations\n        effort = recommendations["estimated_effort"]\n        assert "immediate_hours" in effort\n        assert "short_term_days" in effort\n        assert "long_term_weeks" in effort\n\n    @pytest.mark.slow\n    def test_report_metadata_completeness(\n        self, \n        workflow_file: Path, \n        sample_c2_alert: Dict[str, Any]\n    ):\n        """测试报告元数据完整性"""\n        result = run_workflow(\n            workflow=workflow_file,\n            inputs=sample_c2_alert,\n            trace=False\n        )\n        \n        report = result.outputs.get("analysis_report", {})\n        metadata = report.get("report_metadata", {})\n        \n        # 验证所有必需的元数据字段\n        required_fields = [\n            "title",\n            "version",\n            "generated_at",\n            "report_id",\n            "classification"\n        ]\n        \n        for field in required_fields:\n            assert field in metadata, f"报告元数据缺少{field}字段"\n        \n        # 验证分类的合理性\n        classification = metadata.get("classification", "")\n        valid_classifications = ["PUBLIC", "INTERNAL", "CONFIDENTIAL", "SECRET"]\n        assert classification in valid_classifications, f"无效的分类: {classification}"\n        \n        # 验证报告ID格式\n        report_id = metadata.get("report_id", "")\n        assert report_id.startswith("NDR-RPT-"), f"报告ID格式不正确: {report_id}"\n\n    @pytest.mark.slow\n    def test_executive_summary_quality(\n        self, \n        workflow_file: Path, \n        sample_malware_alert: Dict[str, Any]\n    ):\n        """测试执行摘要质量"""\n        result = run_workflow(\n            workflow=workflow_file,\n            inputs=sample_malware_alert,\n            trace=False\n        )\n        \n        report = result.outputs.get("analysis_report", {})\n        exec_summary = report.get("executive_summary", {})\n        \n        # 验证告警概览\n        alert_overview = exec_summary.get("alert_overview", {})\n        required_alert_fields = [\n            "alert_type", "source_ip", "alert_time", "severity"\n        ]\n        for field in required_alert_fields:\n            assert field in alert_overview, f"告警概览缺少{field}"\n        \n        # 验证风险评估\n        risk_assessment = exec_summary.get("risk_assessment", {})\n        required_risk_fields = [\n            "risk_score", "risk_level", "attack_likelihood", "business_impact"\n        ]\n        for field in required_risk_fields:\n            assert field in risk_assessment, f"风险评估缺少{field}"\n        \n        # 验证关键发现\n        key_findings = exec_summary.get("key_findings", [])\n        assert len(key_findings) > 0, "应该有关键发现"\n\n\n# ==================== 性能和边界测试 ====================\n\nclass TestNDRWorkflowEdgeCases:\n    """测试NDR工作流的边界情况和异常处理"""\n\n    def test_empty_alert_data(\n        self, workflow_file: Path\n    ):\n        """测试空告警数据处理"""\n        empty_inputs = {\n            "alert_data": {},\n            "alert_type": "",\n            "source_ip": ""\n        }\n        \n        result = run_workflow(\n            workflow=workflow_file,\n            inputs=empty_inputs,\n            trace=False\n        )\n        \n        # 即使数据为空，工作流也应该完成执行\n        assert result.status == "SUCCEEDED"\n        assert "analysis_report" in result.outputs\n\n    def test_malformed_json_alert(\n        self, workflow_file: Path\n    ):\n        """测试格式错误的JSON告警数据"""\n        malformed_inputs = {\n            "alert_data": "not valid json{{",\n            "alert_type": "malware",\n            "source_ip": "192.168.1.1"\n        }\n        \n        result = run_workflow(\n            workflow=workflow_file,\n            inputs=malformed_inputs,\n            trace=False\n        )\n        \n        # 应该能够处理格式错误的数据\n        assert result.status == "SUCCEEDED"\n        assert "analysis_report" in result.outputs\n\n    def test_invalid_ip_address(\n        self, workflow_file: Path\n    ):\n        """测试无效IP地址处理"""\n        invalid_ip_inputs = {\n            "alert_data": {"timestamp": "2026-02-12T08:00:00Z"},\n            "alert_type": "malware",\n            "source_ip": "999.999.999.999",  # 无效IP\n            "destination_ip": "not_an_ip",  # 无效IP\n            "severity": "high"\n        }\n        \n        result = run_workflow(\n            workflow=workflow_file,\n            inputs=invalid_ip_inputs,\n            trace=False\n        )\n        \n        # 应该能够处理无效IP\n        assert result.status == "SUCCEEDED"\n        assert "analysis_report" in result.outputs\n\n    @pytest.mark.slow\n    def test_large_alert_data(\n        self, workflow_file: Path\n    ):\n        """测试大型告警数据处理"""\n        # 创建包含大量IOC的告警数据\n        large_alert_data = {\n            "timestamp": "2026-02-12T08:00:00Z",\n            "description": "Large scale attack detected",\n            "events": []\n        }\n        \n        # 添加100个事件\n        for i in range(100):\n            large_alert_data["events"].append({\n                "event_id": f"EVT-{i}",\n                "source_ip": f"192.168.{i//256}.{i%256}",\n                "timestamp": f"2026-02-12T08:{i//60:02d}:{i%60:02d}Z"\n            })\n        \n        large_inputs = {\n            "alert_data": large_alert_data,\n            "alert_type": "malware",\n            "source_ip": "192.168.1.1",\n            "severity": "high"\n        }\n        \n        result = run_workflow(\n            workflow=workflow_file,\n            inputs=large_inputs,\n            trace=False\n        )\n        \n        # 应该能够处理大型数据\n        assert result.status == "SUCCEEDED"\n        assert "analysis_report" in result.outputs\n\n\n# ==================== 集成测试 ====================\n\nclass TestNDRWorkflowIntegration:\n    """测试NDR工作流集成场景"""\n\n    @pytest.mark.slow\n    def test_multiple_alert_sequential_processing(\n        self, \n        workflow_file: Path,\n        sample_malware_alert: Dict[str, Any],\n        sample_c2_alert: Dict[str, Any],\n        sample_low_risk_alert: Dict[str, Any]\n    ):\n        """测试多个告警顺序处理"""\n        results = []\n        \n        for i, alert in enumerate([sample_malware_alert, sample_c2_alert, sample_low_risk_alert]):\n            result = run_workflow(\n                workflow=workflow_file,\n                inputs=alert,\n                trace=False\n            )\n            results.append(result)\n            \n            assert result.status == "SUCCEEDED", f"第{i+1}个告警处理失败"\n            assert "analysis_report" in result.outputs\n        \n        # 验证不同告警产生不同的风险评分\n        malware_risk = results[0].outputs.get("risk_score", 0)\n        c2_risk = results[1].outputs.get("risk_score", 0)\n        low_risk = results[2].outputs.get("risk_score", 0)\n        \n        # C2告警应该有最高风险评分\n        assert c2_risk >= malware_risk or c2_risk >= low_risk, "C2告警应该有较高风险评分"\n        # 低风险告警应该有最低风险评分\n        assert low_risk <= malware_risk or low_risk <= c2_risk, "低风险告警应该有较低风险评分"\n\n    @pytest.mark.slow\n    def test_workflow_idempotency(\n        self, \n        workflow_file: Path, \n        sample_malware_alert: Dict[str, Any]\n    ):\n        """测试工作流执行的幂等性"""\n        # 运行两次相同的输入\n        result1 = run_workflow(\n            workflow=workflow_file,\n            inputs=sample_malware_alert,\n            trace=False\n        )\n        \n        result2 = run_workflow(\n            workflow=workflow_file,\n            inputs=sample_malware_alert,\n            trace=False\n        )\n        \n        # 两次执行都应该成功\n        assert result1.status == "SUCCEEDED"\n        assert result2.status == "SUCCEEDED"\n        \n        # 风险评分应该相同或非常接近\n        risk1 = result1.outputs.get("risk_score", 0)\n        risk2 = result2.outputs.get("risk_score", 0)\n        assert abs(risk1 - risk2) < 0.01, f"风险评分应该一致，第一次{risk1}，第二次{risk2}"\n        \n        # 风险等级应该相同\n        level1 = result1.outputs.get("risk_level", "")\n        level2 = result2.outputs.get("risk_level", "")\n        assert level1 == level2, f"风险等级应该一致，第一次{level1}，第二次{level2}"\n\n\n# ==================== 性能测试 ====================\n\nclass TestNDRWorkflowPerformance:\n    """测试NDR工作流性能"""\n\n    @pytest.mark.slow\n    @pytest.mark.performance\n    def test_workflow_execution_time(\n        self, \n        workflow_file: Path, \n        sample_malware_alert: Dict[str, Any]\n    ):\n        """测试工作流执行时间"""\n        import time\n        \n        start_time = time.time()\n        \n        result = run_workflow(\n            workflow=workflow_file,\n            inputs=sample_malware_alert,\n            trace=False\n        )\n        \n        end_time = time.time()\n        execution_time = end_time - start_time\n        \n        assert result.status == "SUCCEEDED"\n        # 工作流应该在合理时间内完成（例如60秒）\n        assert execution_time < 60, f"工作流执行时间过长: {execution_time:.2f}秒"\n\n    @pytest.mark.slow\n    @pytest.mark.performance\n    def test_workflow_memory_usage(\n        self, \n        workflow_file: Path, \n        sample_malware_alert: Dict[str, Any]\n    ):\n        """测试工作流内存使用"""\n        import psutil\n        import os\n        \n        process = psutil.Process(os.getpid())\n        memory_before = process.memory_info().rss / 1024 / 1024  # MB\n        \n        result = run_workflow(\n            workflow=workflow_file,\n            inputs=sample_malware_alert,\n            trace=False\n        )\n        \n        memory_after = process.memory_info().rss / 1024 / 1024  # MB\n        memory_increase = memory_after - memory_before\n        \n        assert result.status == "SUCCEEDED"\n        # 内存增加应该合理（例如不超过500MB）\n        assert memory_increase < 500, f"工作流内存使用过多: {memory_increase:.2f}MB"\n\n\n# ==================== 安全性测试 ====================\n\nclass TestNDRWorkflowSecurity:\n    """测试NDR工作流安全性"""\n\n    def test_no_code_injection_in_alert_data(\n        self, \n        workflow_file: Path\n    ):\n        """测试告警数据中不包含代码注入"""\n        malicious_alert = {\n            "alert_data": {\n                "description": "Suspicious activity __import__(\'os\').system(\'rm -rf /\')",\n                "timestamp": "2026-02-12T08:00:00Z",\n                "malicious_code": "exec(\'print(1)\')"\n            },\n            "alert_type": "malware",\n            "source_ip": "192.168.1.1",\n            "severity": "high"\n        }\n        \n        result = run_workflow(\n            workflow=workflow_file,\n            inputs=malicious_alert,\n            trace=False\n        )\n        \n        # 工作流应该能够安全地处理包含可疑代码的输入\n        assert result.status == "SUCCEEDED"\n        assert "analysis_report" in result.outputs\n\n    def test_sensitive_data_handling(\n        self, \n        workflow_file: Path\n    ):\n        """测试敏感数据处理"""\n        sensitive_alert = {\n            "alert_data": {\n                "description": "Data breach attempt",\n                "timestamp": "2026-02-12T08:00:00Z",\n                "sensitive_info": {\n                    "api_key": "sk-1234567890abcdef",\n                    "password": "SuperSecret123!",\n                    "credit_card": "4111-1111-1111-1111"\n                }\n            },\n            "alert_type": "exfiltration",\n            "source_ip": "192.168.1.100",\n            "severity": "critical"\n        }\n        \n        result = run_workflow(\n            workflow=workflow_file,\n            inputs=sensitive_alert,\n            trace=False\n        )\n        \n        # 工作流应该能够处理包含敏感数据的输入\n        assert result.status == "SUCCEEDED"\n        assert "analysis_report" in result.outputs\n\n\n# ==================== 主函数入口 ====================\n\nif __name__ == "__main__":\n    """直接运行测试"""\n    # 使用pytest运行所有测试\n    pytest.main([\n        __file__,\n        "-v",\n        "--tb=short",\n        "-m", "not slow"  # 默认跳过慢速测试\n    ])\n'
